SELECT ?actor ?actorLabel WHERE {
  wd:Q47221 wdt:P166 ?award.
  ?award rdfs:label ?awardLabel.
  FILTER (lang(?awardLabel) = "en" && CONTAINS(LCASE(?awardLabel), "best actor"))
  ?award wdt:P746 wd:Q1638418.
  ?award wdt:P2302 ?actor.
  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en".
  }
}

